// Parse meta LLM + brand-guard (no brand reali) + UPDATE SQL.
function lit(s){return String(s).replace(/'/g,"''");}
const BAN=/youtube|google|facebook|instagram|tiktok|amazon|reddit|twitch|outbrain/i;
const out=[];
for (const it of $input.all()){
  const s=it.json;
  // job_id/lang vengono dal nodo Pick (stesso item index)
  const src=$('Pick ready').all()[$input.all().indexOf(it)].json;
  let p={};
  try{p=JSON.parse(s.response||s.data||s.body||'{}');}catch{p={};}
  let title=(p.title||src.title_hint||'AdOff').trim();
  let desc=(p.description||'').trim();
  let tags=Array.isArray(p.tags)?p.tags:[];
  let guard='ok';
  if(!title||BAN.test(title)||BAN.test(desc)){
    title=(src.title_hint||'AdOff — zero pubblicità, ovunque').slice(0,100);
    desc='Blocca ogni pubblicità in modo invisibile. -> adoff.app\n\n🤖 Canale assistito da AI';
    tags=['adblock','privacy','navigazione','no ads','browser','sicurezza'];
    guard='fallback';
  }
  tags=tags.filter(t=>!BAN.test(t)).slice(0,15);
  const tagsLit='ARRAY['+tags.map(t=>`'${lit(t)}'`).join(',')+']::text[]';
  const sql=`UPDATE adoff_autopilot.youtube_queue SET `+
    `yt_title='${lit(title.slice(0,100))}',`+
    `yt_desc='${lit(desc.slice(0,4900))}',`+
    `yt_tags=${tags.length?tagsLit:'NULL'} `+
    `WHERE job_id='${lit(src.job_id)}';`;
  out.push({json:{job_id:src.job_id,title,guard,sql}});
}
return out;

const out=[];
for (const it of $input.all()){
  let r={};
  try{r=JSON.parse((it.json.stdout||'').trim().split('\n').pop());}catch{r={};}
  const url=r.url||'(vedi log)';
  const jid=r.job_id||'?';
  out.push({json:{text:`✅ *YouTube pubblicato*\njob: ${jid}\nvariante: ${r.variant||'?'}\n${url}\n(privacy=private: rivedi e rendi pubblico)`}});
}
return out;
